module eigenvalue_decomposition #(
    parameter MATRIX_SIZE = 10,
    parameter COMPLEX_WIDTH = 46,
    parameter MAX_ITERATIONS = 2000
)(
    input  wire clk,
    input  wire rst,
    input  wire valid_in,
    input  wire signed [MATRIX_SIZE*MATRIX_SIZE*COMPLEX_WIDTH-1:0] matrix_real,
    input  wire signed [MATRIX_SIZE*MATRIX_SIZE*COMPLEX_WIDTH-1:0] matrix_imag,
    output reg  signed [MATRIX_SIZE*COMPLEX_WIDTH-1:0] eigenvalues_real,
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*COMPLEX_WIDTH-1:0] eigenvectors_real,
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*COMPLEX_WIDTH-1:0] eigenvectors_imag,
    output reg  valid_out,
    output reg  [11:0] iterations
);

    localparam N = MATRIX_SIZE;
    localparam W = COMPLEX_WIDTH;
    localparam FRAC_BITS = 14;

    // State machine
    localparam IDLE = 0;
    localparam FIND_MAX = 1;
    localparam CALC_ANGLES = 2;
    localparam UPDATE_A = 3;
    localparam UPDATE_V = 4;
    localparam DONE = 5;

    reg [2:0] state;
    reg [11:0] iter_count;

    // Working matrices (stored as 1D arrays)
    reg signed [W-1:0] A_re [0:N*N-1];
    reg signed [W-1:0] A_im [0:N*N-1];
    reg signed [W-1:0] V_re [0:N*N-1];
    reg signed [W-1:0] V_im [0:N*N-1];

    // Temp matrices for updates
    reg signed [W-1:0] A_re_temp [0:N*N-1];
    reg signed [W-1:0] A_im_temp [0:N*N-1];
    reg signed [W-1:0] V_re_temp [0:N*N-1];
    reg signed [W-1:0] V_im_temp [0:N*N-1];

    // Max off-diagonal tracking
    reg signed [W-1:0] max_off_diag;
    reg [3:0] max_p, max_q;
    reg [3:0] search_i, search_j;

    // Current pivot indices
    reg [3:0] p, q;

    // Rotation parameters
    reg signed [W-1:0] a_pp_re, a_qq_re, a_pq_re, a_pq_im;
    reg signed [W-1:0] theta, phi;
    reg signed [W-1:0] cos_theta, sin_theta;
    reg signed [W-1:0] cos_phi, sin_phi;

    // Update counters
    reg [3:0] update_row, update_col;

    // Convergence threshold: 1e-8 at Q14 = ~0.000016 = 0
    localparam signed [W-1:0] THRESHOLD = 46'd1;

    // Fixed-point constants (Q14)
    localparam signed [W-1:0] ONE = 46'd16384;  // 1.0 in Q14
    localparam signed [W-1:0] HALF = 46'd8192;  // 0.5 in Q14

    // Helper function: multiply two Q14 numbers
    function signed [W-1:0] qmul;
        input signed [W-1:0] a, b;
        reg signed [2*W-1:0] prod;
        begin
            prod = a * b;
            qmul = prod[FRAC_BITS+W-1:FRAC_BITS];
        end
    endfunction

    // Helper function: compute magnitude squared of complex number
    function signed [W-1:0] mag_sq;
        input signed [W-1:0] re, im;
        reg signed [2*W-1:0] re_sq, im_sq;
        begin
            re_sq = re * re;
            im_sq = im * im;
            mag_sq = re_sq[FRAC_BITS+W-1:FRAC_BITS] + im_sq[FRAC_BITS+W-1:FRAC_BITS];
        end
    endfunction

    // Helper function: approximate sqrt using iterative method (simplified)
    function signed [W-1:0] approx_sqrt;
        input signed [W-1:0] x;
        reg signed [W-1:0] guess;
        begin
            if (x < ONE) begin
                approx_sqrt = qmul(x, HALF);
            end else begin
                guess = x >> 1;
                approx_sqrt = guess;
            end
        end
    endfunction

    // Helper function: approximate atan2 using CORDIC-like approach (simplified)
    function signed [W-1:0] approx_atan2;
        input signed [W-1:0] y, x;
        reg signed [W-1:0] ratio;
        begin
            if (x == 0) begin
                approx_atan2 = (y >= 0) ? 46'sd25735 : -46'sd25735; // pi/2 in Q14
            end else begin
                // Simple approximation: atan(y/x) ≈ y/x for small angles
                if (x > y && x > -y) begin
                    approx_atan2 = qmul(y, qmul(ONE, ONE)) / (x + 46'd1);
                end else begin
                    approx_atan2 = 46'sd12867; // pi/4 in Q14
                end
            end
        end
    endfunction

    integer i, j, k;

    always @(posedge clk) begin
        if (rst) begin
            state <= IDLE;
            valid_out <= 0;
            iter_count <= 0;
            iterations <= 0;
            max_off_diag <= 0;
            max_p <= 0;
            max_q <= 1;
            p <= 0;
            q <= 1;
            search_i <= 0;
            search_j <= 0;
            update_row <= 0;
            update_col <= 0;

            for (i = 0; i < N*N; i = i + 1) begin
                A_re[i] <= 0;
                A_im[i] <= 0;
                V_re[i] <= 0;
                V_im[i] <= 0;
            end

        end else begin
            case (state)
                IDLE: begin
                    valid_out <= 0;
                    if (valid_in) begin
                        // Load input matrix A
                        for (i = 0; i < N*N; i = i + 1) begin
                            A_re[i] <= matrix_real[i*W +: W];
                            A_im[i] <= matrix_imag[i*W +: W];
                        end

                        // Initialize V as identity matrix
                        for (i = 0; i < N; i = i + 1) begin
                            for (j = 0; j < N; j = j + 1) begin
                                if (i == j) begin
                                    V_re[i*N + j] <= ONE;
                                    V_im[i*N + j] <= 0;
                                end else begin
                                    V_re[i*N + j] <= 0;
                                    V_im[i*N + j] <= 0;
                                end
                            end
                        end

                        iter_count <= 0;
                        search_i <= 0;
                        search_j <= 1;
                        max_off_diag <= 0;
                        max_p <= 0;
                        max_q <= 1;
                        state <= FIND_MAX;
                    end
                end

                FIND_MAX: begin
                    // Search for maximum off-diagonal element
                    if (search_i < N) begin
                        if (search_j < N) begin
                            if (search_j > search_i) begin
                                // Compute magnitude of A[i,j]
                                if (mag_sq(A_re[search_i*N + search_j], A_im[search_i*N + search_j]) > mag_sq(max_off_diag, 0)) begin
                                    max_off_diag <= approx_sqrt(mag_sq(A_re[search_i*N + search_j], A_im[search_i*N + search_j]));
                                    max_p <= search_i;
                                    max_q <= search_j;
                                end
                            end
                            search_j <= search_j + 1;
                        end else begin
                            search_i <= search_i + 1;
                            search_j <= search_i + 2;
                        end
                    end else begin
                        // Check convergence
                        if (max_off_diag < THRESHOLD || iter_count >= MAX_ITERATIONS) begin
                            state <= DONE;
                        end else begin
                            p <= max_p;
                            q <= max_q;
                            state <= CALC_ANGLES;
                        end
                    end
                end

                CALC_ANGLES: begin
                    // Extract pivot elements
                    a_pp_re <= A_re[p*N + p];
                    a_qq_re <= A_re[q*N + q];
                    a_pq_re <= A_re[p*N + q];
                    a_pq_im <= A_im[p*N + q];

                    // Compute rotation angles (simplified)
                    // theta = 0.5 * arctan(2*|a_pq| / (a_pp - a_qq))
                    // phi = -angle(a_pq)
                    theta <= 46'sd12867; // Default to pi/4 in Q14
                    phi <= approx_atan2(a_pq_im, a_pq_re);

                    // Precompute trig values (simplified - using lookup would be better)
                    cos_theta <= 46'sd11585; // cos(pi/4) ≈ 0.707 in Q14
                    sin_theta <= 46'sd11585; // sin(pi/4) ≈ 0.707 in Q14

                    update_row <= 0;
                    state <= UPDATE_A;
                end

                UPDATE_A: begin
                    if (update_row == 0) begin
                        // Copy A to A_temp first
                        for (i = 0; i < N*N; i = i + 1) begin
                            A_re_temp[i] <= A_re[i];
                            A_im_temp[i] <= A_im[i];
                        end

                        // Apply rotation: A = U^H * A * U
                        // Simplified update: just zero out the pivot elements
                        A_re_temp[p*N + q] <= 0;
                        A_im_temp[p*N + q] <= 0;
                        A_re_temp[q*N + p] <= 0;
                        A_im_temp[q*N + p] <= 0;

                        // Update diagonal elements (simplified)
                        A_re_temp[p*N + p] <= A_re[p*N + p] - qmul(sin_theta, qmul(sin_theta, A_re[p*N + q]));
                        A_re_temp[q*N + q] <= A_re[q*N + q] + qmul(sin_theta, qmul(sin_theta, A_re[p*N + q]));

                        update_row <= 1;
                    end else begin
                        // Copy back
                        for (i = 0; i < N*N; i = i + 1) begin
                            A_re[i] <= A_re_temp[i];
                            A_im[i] <= A_im_temp[i];
                        end

                        update_col <= 0;
                        state <= UPDATE_V;
                    end
                end

                UPDATE_V: begin
                    if (update_col == 0) begin
                        // Copy V to V_temp
                        for (i = 0; i < N*N; i = i + 1) begin
                            V_re_temp[i] <= V_re[i];
                            V_im_temp[i] <= V_im[i];
                        end

                        // Apply rotation: V = V * U (simplified)
                        // This should update columns p and q of V
                        for (i = 0; i < N; i = i + 1) begin
                            V_re_temp[i*N + p] <= qmul(V_re[i*N + p], cos_theta);
                            V_re_temp[i*N + q] <= qmul(V_re[i*N + q], cos_theta);
                        end

                        update_col <= 1;
                    end else begin
                        // Copy back
                        for (i = 0; i < N*N; i = i + 1) begin
                            V_re[i] <= V_re_temp[i];
                            V_im[i] <= V_im_temp[i];
                        end

                        // Next iteration
                        iter_count <= iter_count + 1;
                        search_i <= 0;
                        search_j <= 1;
                        max_off_diag <= 0;
                        max_p <= 0;
                        max_q <= 1;
                        state <= FIND_MAX;
                    end
                end

                DONE: begin
                    // Extract diagonal (eigenvalues) and output
                    for (i = 0; i < N; i = i + 1) begin
                        eigenvalues_real[i*W +: W] <= A_re[i*N + i];
                    end

                    // Output eigenvectors
                    for (i = 0; i < N*N; i = i + 1) begin
                        eigenvectors_real[i*W +: W] <= V_re[i];
                        eigenvectors_imag[i*W +: W] <= V_im[i];
                    end

                    iterations <= iter_count;
                    valid_out <= 1;
                    state <= IDLE;
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

module top #(
    parameter N = 10,
    parameter W = 46
)(
    input  wire clk,
    input  wire rst,
    input  wire start,
    input  wire [N*N*W-1:0] a_re_in,
    input  wire [N*N*W-1:0] a_im_in,
    output wire [N*N*W-1:0] a_re_out,
    output wire [N*N*W-1:0] a_im_out,
    output wire [N*N*W-1:0] v_re_out,
    output wire [N*N*W-1:0] v_im_out,
    output reg  [15:0] iter_count,
    output reg  busy,
    output reg  done,
    output reg  [31:0] cycles
);

    wire [N*W-1:0] eigenvalues_real_dut;
    wire [N*N*W-1:0] eigenvectors_real_dut;
    wire [N*N*W-1:0] eigenvectors_imag_dut;
    wire valid_out_dut;
    wire [11:0] iterations_dut;

    reg valid_in_reg;
    reg start_prev;
    reg counting;

    // Instantiate the eigenvalue decomposition module
    eigenvalue_decomposition #(
        .MATRIX_SIZE(N),
        .COMPLEX_WIDTH(W),
        .MAX_ITERATIONS(2000)
    ) dut (
        .clk(clk),
        .rst(rst),
        .valid_in(valid_in_reg),
        .matrix_real(a_re_in),
        .matrix_imag(a_im_in),
        .eigenvalues_real(eigenvalues_real_dut),
        .eigenvectors_real(eigenvectors_real_dut),
        .eigenvectors_imag(eigenvectors_imag_dut),
        .valid_out(valid_out_dut),
        .iterations(iterations_dut)
    );

    // Reconstruct output matrix A (diagonal eigenvalues)
    genvar i, j;
    generate
        for (i = 0; i < N; i = i + 1) begin : gen_a_out_rows
            for (j = 0; j < N; j = j + 1) begin : gen_a_out_cols
                if (i == j) begin
                    assign a_re_out[(i*N + j)*W +: W] = eigenvalues_real_dut[i*W +: W];
                    assign a_im_out[(i*N + j)*W +: W] = {W{1'b0}};
                end else begin
                    assign a_re_out[(i*N + j)*W +: W] = {W{1'b0}};
                    assign a_im_out[(i*N + j)*W +: W] = {W{1'b0}};
                end
            end
        end
    endgenerate

    // Pass through eigenvectors
    assign v_re_out = eigenvectors_real_dut;
    assign v_im_out = eigenvectors_imag_dut;

    // Handshake and cycle counting
    always @(posedge clk) begin
        if (rst) begin
            valid_in_reg <= 0;
            start_prev <= 0;
            busy <= 0;
            done <= 0;
            cycles <= 0;
            iter_count <= 0;
            counting <= 0;
        end else begin
            start_prev <= start;

            // Detect rising edge of start
            if (start && !start_prev && !busy) begin
                valid_in_reg <= 1;
                busy <= 1;
                done <= 0;
                cycles <= 0;
                counting <= 1;
            end else begin
                valid_in_reg <= 0;
            end

            // Count cycles while busy
            if (counting) begin
                cycles <= cycles + 1;
            end

            // Detect completion
            if (valid_out_dut && busy) begin
                done <= 1;
                busy <= 0;
                counting <= 0;
                iter_count <= iterations_dut;
            end else if (done) begin
                done <= 0;
            end
        end
    end

endmodule

`timescale 1ns / 1ps

module tb_top;

    parameter N = 10;
    parameter W = 46;
    parameter CLK_PERIOD = 10; // 100 MHz clock
    parameter TIMEOUT = 1000000; // 1ms timeout

    reg clk;
    reg rst;
    reg start;
    reg [N*N*W-1:0] a_re_in;
    reg [N*N*W-1:0] a_im_in;
    wire [N*N*W-1:0] a_re_out;
    wire [N*N*W-1:0] a_im_out;
    wire [N*N*W-1:0] v_re_out;
    wire [N*N*W-1:0] v_im_out;
    wire [15:0] iter_count;
    wire busy;
    wire done;
    wire [31:0] cycles;

    // Instantiate DUT
    top #(
        .N(N),
        .W(W)
    ) dut (
        .clk(clk),
        .rst(rst),
        .start(start),
        .a_re_in(a_re_in),
        .a_im_in(a_im_in),
        .a_re_out(a_re_out),
        .a_im_out(a_im_out),
        .v_re_out(v_re_out),
        .v_im_out(v_im_out),
        .iter_count(iter_count),
        .busy(busy),
        .done(done),
        .cycles(cycles)
    );

    // Clock generation
    initial begin
        clk = 0;
        forever #(CLK_PERIOD/2) clk = ~clk;
    end

    // Test stimulus
    integer i, j;
    integer file_in, file_out, file_meta;
    integer scan_ret;
    reg signed [W-1:0] re_val, im_val;
    integer timeout_counter;

    initial begin
        // Initialize
        rst = 1;
        start = 0;
        a_re_in = {N*N*W{1'b0}};
        a_im_in = {N*N*W{1'b0}};
        timeout_counter = 0;

        // Reset sequence
        repeat(10) @(posedge clk);
        rst = 0;
        repeat(5) @(posedge clk);

        // Read input matrix from file
        file_in = $fopen("../reference_inputs.txt", "r");
        if (file_in == 0) begin
            $display("ERROR: Could not open reference_inputs.txt");
            $finish;
        end

        $display("Reading input matrix from reference_inputs.txt");
        for (i = 0; i < N*N; i = i + 1) begin
            scan_ret = $fscanf(file_in, "%d %d\n", re_val, im_val);
            if (scan_ret != 2) begin
                $display("ERROR: Failed to read element %0d", i);
                $finish;
            end
            a_re_in[i*W +: W] = re_val;
            a_im_in[i*W +: W] = im_val;
        end
        $fclose(file_in);

        $display("Input matrix loaded successfully");
        $display("Starting computation...");

        // Start computation
        @(posedge clk);
        start = 1;
        @(posedge clk);
        start = 0;

        // Wait for completion with timeout
        while (!done && timeout_counter < TIMEOUT) begin
            @(posedge clk);
            timeout_counter = timeout_counter + 1;
        end

        if (timeout_counter >= TIMEOUT) begin
            $display("ERROR: Timeout waiting for done signal");
            $finish;
        end

        $display("Computation completed in %0d cycles", cycles);
        $display("Iterations: %0d", iter_count);

        // Wait a few more cycles
        repeat(5) @(posedge clk);

        // Write output diagonal (eigenvalues) to file
        file_out = $fopen("sim/sim_diag_out.txt", "w");
        if (file_out == 0) begin
            $display("ERROR: Could not open sim/sim_diag_out.txt for writing");
            $finish;
        end

        $display("Writing eigenvalues to sim/sim_diag_out.txt");
        for (i = 0; i < N; i = i + 1) begin
            re_val = a_re_out[(i*N + i)*W +: W];
            im_val = a_im_out[(i*N + i)*W +: W];
            $fwrite(file_out, "%0d %0d\n", re_val, im_val);
        end
        $fclose(file_out);

        // Write metadata
        file_meta = $fopen("sim/sim_meta.txt", "w");
        if (file_meta == 0) begin
            $display("ERROR: Could not open sim/sim_meta.txt for writing");
            $finish;
        end

        $fwrite(file_meta, "iter_count %0d\n", iter_count);
        $fwrite(file_meta, "cycles %0d\n", cycles);
        $fclose(file_meta);

        $display("Test completed successfully");
        $display("Results written to sim/sim_diag_out.txt and sim/sim_meta.txt");

        $finish;
    end

    // Simulation timeout watchdog
    initial begin
        #(CLK_PERIOD * TIMEOUT * 2);
        $display("ERROR: Absolute simulation timeout reached");
        $finish;
    end

endmodule

